        break;
      }
      case 'last_week': {
        const end = new Date(today);
        end.setDate(today.getDate() - today.getDay()); // last Sunday
        const start = new Date(end);
        start.setDate(end.getDate() - 6);
        this.startDate = start;
        this.endDate = end;
        break;
      }
      case 'last_month': {
        const start = new Date(today.getFullYear(), today.getMonth() - 1, 1);
        const end = new Date(today.getFullYear(), today.getMonth(), 0);
        this.startDate = start;
        this.endDate = end;
        break;
      }
      case 'last_quarter': {
        const q = Math.floor(today.getMonth() / 3);
        const start = new Date(today.getFullYear(), (q - 1) * 3, 1);
        const end = new Date(today.getFullYear(), q * 3, 0);
        this.startDate = start;
        this.endDate = end;
        break;
      }
    }

    this.selecting = 'start';
    this.hoverDate = null;
    this.viewDate = new Date(this.startDate!);
    this.buildCalendar();
  }

  prevMonth(): void {
    this.viewDate = new Date(
      this.viewDate.getFullYear(),
      this.viewDate.getMonth() - 1,
      1
    );
    this.buildCalendar();
  }

  nextMonth(): void {
    this.viewDate = new Date(
      this.viewDate.getFullYear(),
      this.viewDate.getMonth() + 1,
      1
    );
    this.buildCalendar();
  }

  onDayHover(day: CalendarDay): void {
    if (this.selecting === 'end' && this.startDate) {
      this.hoverDate = day.date;
      this.buildCalendar();
    }
  }

  onDayClick(day: CalendarDay): void {
    this.selectedPreset = null;

    if (this.selecting === 'start') {
      this.startDate = new Date(day.date);
      this.endDate = null;
      this.hoverDate = null;
      this.selecting = 'end';
    } else {
      const clicked = new Date(day.date);
      if (clicked < this.startDate!) {
        // Clicked before start — swap
        this.endDate = new Date(this.startDate!);
        this.startDate = clicked;
      } else {
        this.endDate = clicked;
      }
      this.selecting = 'start';
      this.hoverDate = null;
    }

    this.buildCalendar();
  }

  confirm(): void {
    if (!this.startDate) return;
    const range: DateRange = {
      start: this.startDate,
      end: this.endDate ?? this.startDate,
      preset: this.selectedPreset ?? undefined,
    };
    this.updateLabel(range);
    this.onChange(range);
    this.rangeSelected.emit(range);
    this.isOpen = false;
  }

  reset(): void {
    this.startDate = null;
    this.endDate = null;
    this.selectedPreset = null;
    this.selecting = 'start';
    this.hoverDate = null;
    this.displayLabel = 'Select date range';
    this.buildCalendar();
    const range: DateRange = { start: null, end: null };
    this.onChange(range);
    this.rangeSelected.emit(range);
  }

  private updateLabel(range: DateRange): void {
    if (this.selectedPreset) {
      const p = PRESETS.find((p) => p.key === this.selectedPreset);
      this.displayLabel = p ? p.label : this.formatRange(range);
    } else {
      this.displayLabel = this.formatRange(range);
    }
  }

  private formatRange(range: DateRange): string {
    const fmt = (d: Date) =>
      d.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric',
      });
    if (!range.start) return 'Select date range';
    if (!range.end || range.start.getTime() === range.end.getTime())
      return fmt(range.start);
    return `${fmt(range.start)} – ${fmt(range.end)}`;
  }

  buildCalendar(): void {
    const year = this.viewDate.getFullYear();
    const month = this.viewDate.getMonth();
    const firstDay = new Date(year, month, 1);
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    // Monday-based: getDay() returns 0=Sun, adjust
    let startOffset = firstDay.getDay() - 1;
    if (startOffset < 0) startOffset = 6;

    const days: CalendarDay[] = [];
    const calStart = new Date(firstDay);
    calStart.setDate(calStart.getDate() - startOffset);

    const effectiveEnd = this.endDate ?? this.hoverDate;

    for (let i = 0; i < 42; i++) {
      const date = new Date(calStart);
      date.setDate(calStart.getDate() + i);
      date.setHours(0, 0, 0, 0);

      const isStart =
        !!this.startDate && date.getTime() === this.startDate.getTime();
      const isEnd =
        !!effectiveEnd && date.getTime() === effectiveEnd.getTime();
      const inRange =
        !!this.startDate &&
        !!effectiveEnd &&
        date > this.startDate &&
        date < effectiveEnd;

      days.push({
        date,
        currentMonth: date.getMonth() === month,
        isToday: date.getTime() === today.getTime(),
        isStart,
        isEnd,
        inRange,
        disabled: false,
      });
    }

    this.calendarDays = days;
  }

  // ControlValueAccessor
  writeValue(value: DateRange): void {
    if (value) {
      this.startDate = value.start;
      this.endDate = value.end;
      this.buildCalendar();
    }
  }
  registerOnChange(fn: (value: DateRange) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
}

styleUrlsData.data:
$font: 'Poppins', system-ui, sans-serif;
$radius-sm: 8px;
$radius-md: 12px;
$radius-lg: 16px;

$color-bg: #ffffff;
$color-surface: #f9f8f6;
$color-border: #e8e5e0;
$color-text: #1a1917;
$color-muted: #a09d98;
$color-accent: #1a1917;
$color-range-bg: #f0ede8;
$color-hover: #f4f2ef;
$color-preset-active: #1a1917;

// Wrapper 
.drp-wrapper {
  position: relative;
  display: inline-block;
  font-family: $font;
  font-size: 14px;
  color: $color-text;
}

// Trigger 
.drp-trigger {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 9px 14px;
  background: $color-bg;
  border: 1.5px solid $color-border;
  border-radius: $radius-md;
  cursor: pointer;
  font-family: $font;
  font-size: 14px;
  color: $color-text;
  white-space: nowrap;
  transition: border-color 0.15s, box-shadow 0.15s;

  &:hover {
    border-color: darken($color-border, 10%);
  }

  &.open {
    border-color: $color-accent;
    box-shadow: 0 0 0 3px rgba(26, 25, 23, 0.08);
  }

  .drp-icon-cal {
    width: 15px;
    height: 15px;
    color: $color-muted;
    flex-shrink: 0;
  }

  .drp-icon-chevron {
    width: 10px;
    height: 6px;
    color: $color-muted;
    flex-shrink: 0;
    transition: transform 0.2s ease;

    &.rotated {
      transform: rotate(180deg);
    }
  }
}

// Panel
.drp-panel {
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  z-index: 1000;
  background: $color-bg;
  border: 1.5px solid $color-border;
  border-radius: $radius-lg;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 2px 8px rgba(0, 0, 0, 0.06);
  overflow: hidden;
  animation: drp-open 0.15s ease;
}

@keyframes drp-open {
  from { opacity: 0; transform: translateY(-4px); }
  to   { opacity: 1; transform: translateY(0); }
}

// Layout
.drp-layout {
  display: flex;
}

// Presets
.drp-presets {
  display: flex;
  flex-direction: column;
  padding: 16px 0;
  border-right: 1.5px solid $color-border;
  min-width: 130px;
  gap: 2px;
}

.drp-preset-btn {
  display: block;
  width: 100%;
  padding: 8px 20px;
  background: none;
  border: none;
  text-align: left;
  font-family: $font;
  font-size: 14px;
  color: $color-text;
  cursor: pointer;
  border-radius: 0;
  transition: background 0.1s;

  &:hover {
    background: $color-hover;
  }

  &.active {
    font-weight: 600;
    color: $color-preset-active;
    background: $color-hover;
  }
}

// Actions
.drp-actions {
  margin-top: auto;
  padding: 16px 20px 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.drp-action-confirm,
.drp-action-reset {
  background: none;
  border: none;
  font-family: $font;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  padding: 4px 0;
  text-align: left;
  color: $color-text;
  transition: opacity 0.15s;

  &:hover {
    opacity: 0.6;
  }
}

.drp-action-reset {
  font-weight: 700;
}

// Calendar
.drp-calendar {
  padding: 16px 20px 20px;
  width: 290px;
}

.drp-cal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 14px;
}

.drp-month-label {
  font-weight: 700;
  font-size: 15px;
}

.drp-nav {
  display: flex;
  gap: 4px;
}

.drp-nav-btn {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: none;
  border: 1.5px solid $color-border;
  border-radius: $radius-sm;
  cursor: pointer;
  transition: background 0.1s, border-color 0.1s;

  svg {
    width: 6px;
    height: 10px;
    color: $color-text;
  }

  &:hover {
    background: $color-hover;
    border-color: darken($color-border, 8%);
  }
}

// Grid 
.drp-grid {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  row-gap: 2px;
}

.drp-weekday {
  text-align: center;
  font-size: 12px;
  font-weight: 600;
  color: $color-muted;
  padding-bottom: 8px;
  letter-spacing: 0.02em;
}

// Days
.drp-day {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 36px;
  cursor: pointer;

  &.in-range {
    background: $color-range-bg;
  }

  &.start:not(.end) {
    background: linear-gradient(to left, $color-range-bg 50%, transparent 50%);
  }

  &.end:not(.start) {
    background: linear-gradient(to right, $color-range-bg 50%, transparent 50%);
  }

  &.start.end {
    background: transparent;
  }

  .drp-day-inner {
    position: relative;
    z-index: 1;
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    font-size: 13px;
    transition: background 0.1s, color 0.1s;
  }

  &:hover:not(.start):not(.end) .drp-day-inner {
    background: $color-hover;
  }

  &.other-month {
    .drp-day-inner {
      color: $color-muted;
    }
  }

  &.today:not(.start):not(.end) {
    .drp-day-inner {
      border: 1.5px solid $color-text;
    }
  }

  &.start .drp-day-inner,
  &.end .drp-day-inner {
    background: $color-accent;
    color: #ffffff;
    font-weight: 600;
  }
}

